  const parts = text.split(/(\*\*[^*\n][^*\n]*\*\*|__[^_\n][^_\n]*__)/g);

  if (parts.length === 1) {
    return text;
  }

  return parts.map((part) => {
    const strongMatch =
      part.match(/^\*\*([^*\n][^*\n]*)\*\*$/) ??
      part.match(/^__([^_\n][^_\n]*)__$/);

    if (!strongMatch) {
      return part;
    }

    return <strong key={`strong-${strongMatch[1]}`}>{strongMatch[1]}</strong>;
  });
}"}]

